// Parsear el payload del webhook de Supabase Storage
const item = $input.first().json;

// Supabase webhook envía { type: 'INSERT', table: 'objects', record: {...}, ... }
const record = item.record || item;
const fileName = record.name || record.path_tokens?.[record.path_tokens.length - 1] || 'unknown';
const fileId = record.id || record.metadata?.id || fileName;
const bucketId = record.bucket_id || 'ddna-repositorio';

// Extensiones válidas para procesar
const VALID_EXTENSIONS = ['.pdf', '.docx', '.xlsx', '.txt', '.csv'];
const extension = fileName.toLowerCase().slice(fileName.lastIndexOf('.'));

if (!VALID_EXTENSIONS.includes(extension)) {
  throw new Error(`Tipo de archivo no soportado: ${extension}. Solo: ${VALID_EXTENSIONS.join(', ')}`);
}

// Saltar archivos de sistema (empezados con .)
if (fileName.startsWith('.')) {
  throw new Error('Archivo de sistema ignorado');
}

return [{
  json: {
    file_name: fileName,
    file_id: fileId,
    bucket_id: bucketId,
    file_type: extension.replace('.', ''),
    event_type: item.type || 'INSERT',
    timestamp: new Date().toISOString()
  }
}];

// Determinar cómo extraer texto según el tipo de archivo
const item = $input.first().json;
const fileType = $('Parse Webhook').first().json.file_type;

// Pasar metadata del archivo para que los nodos siguientes la tengan
return [{
  json: {
    ...item,
    file_name: $('Parse Webhook').first().json.file_name,
    file_id: $('Parse Webhook').first().json.file_id,
    file_type: fileType
  }
}];

// Chunk text into ~500 token chunks with 20% overlap
const items = $input.all();
const results = [];

// Obtener metadata del archivo (viene de nodos anteriores)
const parseData = $('Parse Webhook').first().json;
const fileId = parseData.file_id;
const source = parseData.file_name;
const fileType = parseData.file_type;

const MAX_CHARS = 2000;
const OVERLAP_CHARS = Math.floor(MAX_CHARS * 0.2);

for (const item of items) {
  const text = item.json.text || item.json.content || item.json.extractedText || '';

  if (!text || text.length < 50) {
    if (text && text.trim().length > 0) {
      results.push({
        json: {
          repo_file_id: fileId,
          chunk_index: 0,
          content: text.trim(),
          source: source,
          file_type: fileType,
          char_count: text.trim().length,
          word_count: text.trim().split(/\s+/).length,
          processed_at: new Date().toISOString()
        }
      });
    }
    continue;
  }

  let chunkIndex = 0;
  let start = 0;

  while (start < text.length) {
    let end = Math.min(start + MAX_CHARS, text.length);

    if (end < text.length) {
      const window = text.slice(start, end);
      const paraBreak = window.lastIndexOf('\n\n');
      const sentenceBreak = window.lastIndexOf('. ');

      if (paraBreak > MAX_CHARS * 0.4) {
        end = start + paraBreak;
      } else if (sentenceBreak > MAX_CHARS * 0.4) {
        end = start + sentenceBreak + 1;
      }
    }

    const chunkText = text.slice(start, end).trim();
    if (chunkText.length > 30) {
      results.push({
        json: {
          repo_file_id: fileId,
          chunk_index: chunkIndex,
          content: chunkText,
          source: source,
          file_type: fileType,
          char_count: chunkText.length,
          word_count: chunkText.split(/\s+/).length,
          processed_at: new Date().toISOString()
        }
      });
      chunkIndex++;
    }

    start = end - OVERLAP_CHARS;
    if (start >= text.length - 10) break;
  }
}

if (results.length === 0) {
  throw new Error('No se pudo extraer texto del archivo. ¿Formato soportado?');
}

return results;

const items = $input.all();
const chunkItems = $('Chunk Text').all();

return items.map((item, i) => {
  const chunkData = chunkItems[i]?.json || {};
  const embedding = item.json.data?.[0]?.embedding || [];

  return {
    json: {
      repo_file_id: chunkData.repo_file_id || '',
      chunk_index: chunkData.chunk_index || 0,
      content: chunkData.content || '',
      embedding: embedding,
      metadata: {
        source: chunkData.source || '',
        type: chunkData.file_type || 'unknown',
        chunk_size: chunkData.word_count || 0,
        processed_at: chunkData.processed_at || new Date().toISOString()
      }
    }
  };
});

const inserts = $input.all();
const parseData = $('Parse Webhook').first().json;

return [{
  json: {
    status: 'success',
    file: parseData.file_name,
    chunks_indexed: inserts.length,
    timestamp: new Date().toISOString(),
    message: `✅ ${parseData.file_name}: ${inserts.length} chunks indexados`
  }
}];
